.location-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 48px;
  align-items: start;
}

.location-map {
  width: 100%;
  height: 320px;
  border-radius: 4px;
  overflow: hidden;
  border: 1px solid var(--border);
  background: oklch(24% 0.024 50);
  position: relative;
}
.location-map-inner {
  width: 100%;
  height: 100%;
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--cream);
  font: 400 14px/1 var(--font-body);
  color: oklch(70% 0.01 50);
  flex-direction: column;
  gap: 8px;
}
.location-map-inner svg { opacity: 0.5; }

